import{aP as e,Q as r,S as t,ae as h,aQ as n,B as i}from"./framework-050a1604.js";const o={},d=n('<h2 id="pointsmaterial" tabindex="-1"><a class="header-anchor" href="#pointsmaterial" aria-hidden="true">#</a> PointsMaterial</h2><p>Points使用的默认材质。</p><h2 id="构造器" tabindex="-1"><a class="header-anchor" href="#构造器" aria-hidden="true">#</a> 构造器</h2><h3 id="parameters-object" tabindex="-1"><a class="header-anchor" href="#parameters-object" aria-hidden="true">#</a> parameters : Object</h3><p>parameters - (可选)用于定义材质外观的对象，具有一个或多个属性。 材质的任何属性都可以从此处传入(包括从Material继承的任何属性)。</p><p>属性color例外，其可以作为十六进制字符串传递，默认情况下为 0xffffff（白色），内部调用Color.set(color)。</p><h2 id="属性" tabindex="-1"><a class="header-anchor" href="#属性" aria-hidden="true">#</a> 属性</h2><p>共有属性请参见其基类Material。</p><h3 id="alphamap-texture" tabindex="-1"><a class="header-anchor" href="#alphamap-texture" aria-hidden="true">#</a> .alphaMap : Texture</h3><p>alpha贴图是一张灰度纹理，用于控制整个表面的不透明度。（黑色：完全透明；白色：完全不透明）。 默认值为null。</p><p>仅使用纹理的颜色，忽略alpha通道（如果存在）。 对于RGB和RGBA纹理，WebGL渲染器在采样此纹理时将使用绿色通道， 因为在DXT压缩和未压缩RGB 565格式中为绿色提供了额外的精度。 Luminance-only以及luminance/alpha纹理也仍然有效。</p><h3 id="color-color" tabindex="-1"><a class="header-anchor" href="#color-color" aria-hidden="true">#</a> .color : Color</h3><p>材质的颜色(Color)，默认值为白色 (0xffffff)。</p><h3 id="fog-boolean" tabindex="-1"><a class="header-anchor" href="#fog-boolean" aria-hidden="true">#</a> .fog : Boolean</h3><p>材质是否受雾影响。默认为true。</p><h3 id="map-texture" tabindex="-1"><a class="header-anchor" href="#map-texture" aria-hidden="true">#</a> .map : Texture</h3><p>使用来自Texture的数据设置点的颜色。可以选择包括一个alpha通道，通常与 .transparent或.alphaTest。</p><h3 id="size-number" tabindex="-1"><a class="header-anchor" href="#size-number" aria-hidden="true">#</a> .size : Number</h3><p>设置点的大小。默认值为1.0。 Will be capped if it exceeds the hardware dependent parameter gl.ALIASED_POINT_SIZE_RANGE.</p><h3 id="sizeattenuation-boolean" tabindex="-1"><a class="header-anchor" href="#sizeattenuation-boolean" aria-hidden="true">#</a> .sizeAttenuation : Boolean</h3><p>指定点的大小是否因相机深度而衰减。（仅限透视摄像头。）默认为true。</p><h2 id="方法" tabindex="-1"><a class="header-anchor" href="#方法" aria-hidden="true">#</a> 方法</h2><p>共有方法请参见其基类Material</p>',23);function l(p,s){const a=i("IFrame");return r(),t("div",null,[h(a,{url:"https://luotainxu-demo.netlify.app/#/threejs/pointsMaterial"}),d])}const u=e(o,[["render",l],["__file","点材质.html.vue"]]);export{u as default};
